     5→/** Formater une date en français */
     6→export function formatDateFR(dateStr: string): string {
     7→  return new Date(dateStr).toLocaleDateString('fr-FR', {
     8→    day: 'numeric',
     9→    month: 'long',
    10→    year: 'numeric',
    11→  })
    12→}
