    14→/** Formater une date relative (il y a X minutes/heures/jours) */
    15→export function formatRelativeDate(dateStr: string): string {
    16→  const now = new Date()
    17→  const date = new Date(dateStr)
    18→  const diffMs = now.getTime() - date.getTime()
    19→  const diffMinutes = Math.floor(diffMs / 60000)
    20→  const diffHours = Math.floor(diffMs / 3600000)
    21→  const diffDays = Math.floor(diffMs / 86400000)
    22→
    23→  if (diffMinutes < 1) return "À l'instant"
    24→  if (diffMinutes < 60) return `Il y a ${diffMinutes} min`
    25→  if (diffHours < 24) return `Il y a ${diffHours}h`
    26→  if (diffDays < 7) return `Il y a ${diffDays}j`
    27→  return formatDateFR(dateStr)
    28→}
