    43→/** Extraire le domaine d'une URL */
    44→export function extractDomain(url: string): string {
    45→  try {
    46→    const parsed = new URL(url.startsWith('http') ? url : `https://${url}`)
    47→    return parsed.hostname.replace('www.', '')
    48→  } catch {
    49→    return url
    50→  }
    51→}
    52→
    53→/** Valider une URL */
    54→export function isValidUrl(url: string): boolean {
    55→  try {
    56→    const parsed = new URL(url.startsWith('http') ? url : `https://${url}`)
    57→    return parsed.protocol === 'https:' || parsed.protocol === 'http:'
    58→  } catch {
    59→    return false
    60→  }
    61→}
